mapper.select:
select o.id, o.order_no, o.pickup_time, o.total, o.status, creator.name as createName, o.create_time, updater.name as updateName, o.update_time from orders o left join emps creator on o.create_id = creator.id left join emps updater on o.update_id = updater.id
AND o.order_no = #{orderNo}
AND o.status = #{status}
AND o.pickup_time >= CONCAT(#{startDate}, ' 00:00:00') AND o.pickup_time <= CONCAT(#{endDate}, ' 23:59:59')
order by o.status ASC, o.order_no ASC
